import time

class Tweet:
    def __init__(self, tweet_id: int, user_id: str, content: str, timestamp: float):
        self.tweet_id = tweet_id
        self.user_id = user_id
        self.content = content
        self.timestamp = timestamp

class User:
    def __init__(self, username: str):
        self.username = username
        self.following = set()
        self.followers = set()

class Twitter:
    def __init__(self):
        self.users = {}
        self.tweets = []
        self._next_tweet_id = 0

    def register_user(self, username: str) -> bool:
        if username in self.users:
            return False
        self.users[username] = User(username)
        return True

    def post_tweet(self, user_id: str, content: str) -> Tweet | None:
        if user_id not in self.users:
            return None

        tweet_id = self._next_tweet_id
        self._next_tweet_id += 1
        timestamp = time.time()
        new_tweet = Tweet(tweet_id, user_id, content, timestamp)
        self.tweets.append(new_tweet)
        return new_tweet

    def get_news_feed(self, user_id: str, limit: int = 10) -> list[Tweet]:
        if user_id not in self.users:
            return []

        user = self.users[user_id]
        feed_sources = {user_id} | user.following

        news_feed = []
        for tweet in reversed(self.tweets):
            if tweet.user_id in feed_sources:
                news_feed.append(tweet)
            if len(news_feed) >= limit:
                break
        return news_feed

    def follow(self, follower_id: str, followee_id: str) -> bool:
        if follower_id not in self.users or followee_id not in self.users:
            return False
        if follower_id == followee_id:
            return False

        follower = self.users[follower_id]
        followee = self.users[followee_id]

        follower.following.add(followee_id)
        followee.followers.add(follower_id)
        return True

    def unfollow(self, follower_id: str, followee_id: str) -> bool:
        if follower_id not in self.users or followee_id not in self.users:
            return False

        follower = self.users[follower_id]
        followee = self.users[followee_id]

        if followee_id in follower.following:
            follower.following.discard(followee_id)
            followee.followers.discard(follower_id)
            return True
        return False
